features.snippet:
interface ch_if;
  logic valid;
  logic [7:0] data;
  modport master (output valid, data, input clk);
endinterface

logic sig;
ch_if ch();
assign sig = ch.valid;

interface channel_if;
  logic valid;
endinterface

interface multi_channel_if;
  channel_if ch1();
  channel_if ch2();
endinterface

module top;
  multi_channel_if mch();
endmodule

module child(input multi_channel_if mch);
endmodule
